# FONTSET fixture: aliases declared via FONTSET should be resolved to the
# real font family name at translate time and reflected in every LABEL.FONT
# reference in the emitted YAML.
MAP
  NAME "fontset_demo"
  TITLE "Font alias resolution"
  FONTSET "fonts.list"

  LAYER
    NAME "places"
    TYPE POINT
    STATUS ON
    DATA "geom FROM places"
    PROCESSING "ITEMS=ogc_fid,name"

    CLASS
      NAME "default"
      STYLE
        COLOR 32 32 32
        WIDTH 1
      END
    END

    LABEL
      TEXT "[name]"
      FONT "sans"
      SIZE 10
      COLOR 0 0 0
    END
  END
END
